select

from stat_battery_bat pack



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) >= strftime('%Y-%m-%d %H:%M:%S',
        #{params.beginTime})



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) <= strftime('%Y-%m-%d %H:%M:%S',
        #{params.endTime})


        and config_id = #{configId}


        and pack_num = #{packNum}


        and bat_num = #{batNum}


order by create_time ${isAsc}

select

from stat_battery_bat pack



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) >= strftime('%Y-%m-%d %H:%M:%S',
        #{startDateTime})



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) <= strftime('%Y-%m-%d %H:%M:%S', #{endDateTime})


        and config_id = #{configId}


        and pack_num = #{packNum}


        and bat_num = #{batNum}


order by create_time asc
